function getBookJd(bookId) {
    return new Promise((resolve, reject) => {
        const sql = 'SELECT jdID FROM bookjd WHERE bookId = ?';
        db.query(sql, bookId, (err, results) => {
            if (err) {
                reject('0');
            }
            if (results.length > 0) {
                resolve(results[0].jdID);
            }
            reject(results);
        });
    });
}
