async function dtFile(req, res) {
    let dtId = req.query.dtid;
    if (!dtId) {
        return res.send({
            code: 401,
        });
    }
    let fileObj = await (0, dt_1.findFile)(dtId.toString());
    if (!fileObj || fileObj.length == 0) {
        return res.send({
            code: 401,
        });
    }
    let fileSrc = (0, pathUtils_1.getUrl)('root', 'assets/file', fileObj[0].file_src);
    // 检查文件是否存在
    fs_1.default.access(fileSrc, fs_1.default.constants.F_OK, (err) => {
        if (err) {
            // 文件不存在，返回 404 错误
            return res.status(404).send('File not found');
        }
        // 设置下载的文件名（可选，你可以从 file_src 中提取或设置其他名称）
        // let expandName = fileObj[0].file_src.split('.')[fileObj[0].file_src.split('.').length -1 ];
        const fileName = path_1.default.basename(fileObj[0].name + "&&" + fileObj[0].file_src);
        res.download(fileSrc, fileName, (err) => {
            if (err) {
                // 处理下载错误
                console.error('Error downloading file:', err);
                res.status(500).send('Error downloading file');
            }
            else {
                // 下载成功
                console.log('File downloaded successfully');
            }
        });
    });
}
function generateRandomString(length) {
    const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let result = '';
    const charactersLength = characters.length;
    for (let i = 0; i < length; i++) {
        const randomIndex = Math.floor(Math.random() * charactersLength);
        result += characters[randomIndex];
    }
    return result;
}
